    "quantities.open": "Öffnen",
    "quantities.open_boq": "LV-Editor öffnen",
    "quantities.step1_desc": "Wählen Sie Ihre Eingabemethode: Text, PDF oder CAD-Modell.",
    "quantities.step1_title": "Hochladen oder beschreiben",
    "quantities.step2_desc": "Unsere KI analysiert Ihre Eingabe und extrahiert strukturierte Mengen.",
